# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests

# RabbitMQ management API endpoint
api_url = "http://localhost:15672/api/vhosts"

# List of virtual hosts to create
vhosts = {
    "app1": {},
    "app2": {},
}

# Create virtual hosts
for vhost_name, vhost_config in vhosts.items():
    response = requests.put(f"{api_url}/{vhost_name}", json=vhost_config)
    if not response.ok:
        raise Exception(f"Failed to create vhost: {vhost_name}")

# Create users
users = {
    "user1": {"password": "password1"},
    "user2": {"password": "password2"},
}

for user_name, user_config in users.items():
    response = requests.put(f"{api_url}/{user_name}", json=user_config)
    if not response.ok:
        raise Exception(f"Failed to create user: {user_name}")

# Grant permissions for queue operations
permissions = {
    "app1": {"user1": {"configure": True, "write": True, "read": True}},
    "app2": {"user2": {"configure": True, "write": True, "read": True}},
}

for vhost_name, user_permissions in permissions.items():
    for user_name, permissions in user_permissions.items():
        response = requests.put(
            f"{api_url}/{vhost_name}/permissions/{user_name}", json=permissions
        )
        if not response.ok:
            raise Exception(f"Failed to grant permissions for user: {user_name}")

print("Virtual hosts, users, and permissions configured successfully.")